```rust
// AFTER
pub fn execute(args: &Args, ctx: &OutputContext, overrides: &CliOverrides) -> Result<()> {
    let issues = fetch_issues(args, overrides)?;

    if ctx.is_json() {
        ctx.json(&issues);
        return Ok(());
    }

    IssueTable::new(&issues, ctx).render()
}
